string pad(int num) {

  string t = to_string(num);

  string pad = "";

  if (t.size() < 6) {

    int diff = 6 - (int) t.size();

    for (int i = 0; i < diff; ++i) {

      pad += '0';

    }

  }

  return pad + t;

}



struct task{

  int year, id;

};



