  ios_base::sync_with_stdio(false);

  cin.tie(nullptr);



  int n, m; cin >> n >> m;

  vector<task> v[101010];

  for (int i = 0; i < m; ++i) {

    int p, y; cin >> p >> y;

    v[p].push_back({y, i + 1});

  }



  vector<string> ans(m + 1);



  for (int i = 1; i <= n; ++i) {

    if (v[i].empty()) continue;

    sort(v[i].begin(), v[i].end(), [](const task &x, const task &y){

      return x.year < y.year;

    });

  }



  for (int i = 1; i <= n; ++i) {

    for (int j = 0; j < (int)v[i].size(); ++j) {

      ans[v[i][j].id] = pad(i) + pad(j + 1);

    }

  }



  for (int i = 1; i <= m; ++i) {

    cout << ans[i] << '\n';

  }



  return 0;

